/* ═══════════════════════════════════════════
   INSTANT PURSUIT — Shared Data & Utilities
   ═══════════════════════════════════════════ */
const SITE = { name: 'Instant Pursuit', tagline: 'Navigate your career with confidence.', url: 'https://instantpursuit.in', icon: '🔥' };
const NAV_LINKS = [
  { href: 'index.html', label: 'Home', icon: '🏠' },
  { href: 'explore.html', label: 'Explore', icon: '🗺️' },
  { href: 'blog.html', label: 'Blog', icon: '✍️' },
  { href: 'about.html', label: 'About', icon: '📖' },
];
function getTheme(){return localStorage.getItem('ip-theme')||'dark'}
function setTheme(t){document.documentElement.setAttribute('data-theme',t);localStorage.setItem('ip-theme',t);const b=document.querySelector('.theme-toggle');if(b)b.textContent=t==='dark'?'☀️':'🌙'}
function toggleTheme(){setTheme(getTheme()==='dark'?'light':'dark')}
function initTheme(){setTheme(getTheme())}
function loadData(k,f){try{const d=localStorage.getItem(k);return d?JSON.parse(d):f}catch{return f}}
function saveData(k,v){localStorage.setItem(k,JSON.stringify(v))}
function injectNav(){
  const cur=location.pathname.split('/').pop()||'index.html';
  const n=document.createElement('nav');n.className='ip-nav';
  n.innerHTML=`<div class="ip-nav-inner"><a href="index.html" class="ip-nav-logo">
    <span class="ip-logo-mark" aria-hidden="true">
      <img src="assets/logo.png" alt="" width="40" height="40">
    </span>
    <span class="ip-logo-word"><span class="ip-logo-word-1">Instant</span><span class="ip-logo-word-2">Pursuit</span></span>
  </a><div class="ip-nav-links">${NAV_LINKS.map(l=>`<a href="${l.href}" class="${cur===l.href?'active':''}">${l.label}</a>`).join('')}</div><div class="ip-nav-right"><button class="theme-toggle" onclick="toggleTheme()" title="Toggle theme">🌙</button><button class="ip-hamburger" onclick="document.querySelector('.ip-mobile-menu').classList.toggle('open')" aria-label="Menu"><span></span><span></span><span></span></button></div></div><div class="ip-mobile-menu">${NAV_LINKS.map(l=>`<a href="${l.href}" class="${cur===l.href?'active':''}">${l.icon} ${l.label}</a>`).join('')}</div>`;
  document.body.prepend(n);
}
function injectFooter(){
  const f=document.createElement('footer');f.className='ip-footer';
  f.innerHTML=`<div class="ip-footer-logo">
    <span class="ip-logo-mark" aria-hidden="true">
      <img src="assets/logo.png" alt="" width="36" height="36">
    </span>
    <span class="ip-logo-word"><span class="ip-logo-word-1">Instant</span><span class="ip-logo-word-2">Pursuit</span></span>
  </div><div class="ip-footer-tagline">${SITE.tagline}</div><div class="ip-footer-links">${NAV_LINKS.map(l=>`<a href="${l.href}">${l.label}</a>`).join('')}</div><div class="ip-footer-disclaimer">Disclaimer: This website is maintained in a personal capacity for educational and informational purposes only. It does not represent the views of the Government of India or any department thereof.</div><div class="ip-footer-copy">&copy; 2026 ${SITE.name}. Free for every student.</div>`;
  document.body.appendChild(f);
}
function initPage(){
  initTheme();
  if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){injectNav();injectFooter()})}
  else{injectNav();injectFooter()}
}

